def group_by_grade(students):
    result = {}
    for name, score in students:
        if score >= 90:
            grade = 'A'
        elif score >= 80:
            grade = 'B'
        elif score >= 70:
            grade = 'C'
        elif score >= 60:
            grade = 'D'
        else:
            grade = 'F'
        if grade not in result:
            result[grade] = []
        result[grade].append(name)
    return result

