import unittest

class TestSolution(unittest.TestCase):
    def test_mixed_grades(self):
        result = group_by_grade([("Alice", 95), ("Bob", 82), ("Charlie", 70), ("Diana", 61), ("Eve", 55)])
        self.assertEqual(result, {"A": ["Alice"], "B": ["Bob"], "C": ["Charlie"], "D": ["Diana"], "F": ["Eve"]})

    def test_multiple_same_grade(self):
        result = group_by_grade([("Alice", 95), ("Bob", 92), ("Charlie", 88)])
        self.assertEqual(result, {"A": ["Alice", "Bob"], "B": ["Charlie"]})

    def test_empty_list(self):
        result = group_by_grade([])
        self.assertEqual(result, {})

    def test_hidden_boundary_values(self):
        students = [("A1", 100), ("A2", 90), ("B1", 89), ("B2", 80), ("C1", 79), ("C2", 70), ("D1", 69), ("D2", 60), ("F1", 59), ("F2", 0)]
        result = group_by_grade(students)
        self.assertEqual(result, {"A": ["A1", "A2"], "B": ["B1", "B2"], "C": ["C1", "C2"], "D": ["D1", "D2"], "F": ["F1", "F2"]})

    def test_hidden_all_failing(self):
        result = group_by_grade([("X", 50), ("Y", 40), ("Z", 30)])
        self.assertEqual(result, {"F": ["X", "Y", "Z"]})

    def test_hidden_single_student(self):
        result = group_by_grade([("Solo", 75)])
        self.assertEqual(result, {"C": ["Solo"]})

    def test_hidden_all_as(self):
        result = group_by_grade([("Top1", 100), ("Top2", 99), ("Top3", 90)])
        self.assertEqual(result, {"A": ["Top1", "Top2", "Top3"]})

    def test_hidden_exact_boundaries(self):
        result = group_by_grade([("S1", 90), ("S2", 80), ("S3", 70), ("S4", 60)])
        self.assertEqual(result, {"A": ["S1"], "B": ["S2"], "C": ["S3"], "D": ["S4"]})

if __name__ == '__main__':
    unittest.main()
